angular.module('myApp', [])
.directive('jsonDataGrid', function() {
    return {
        restrict: 'E',
        scope: {
            jsonData: '='
        },
        template: '<div><table><thead><tr><th ng-repeat="(key, value) in headers">{{ key }}</th></tr></thead><tbody><tr ng-repeat="row in data"><td ng-repeat="(key, value) in row">{{ value }}</td></tr></tbody></table></div>',
        link: function(scope) {
            scope.$watch('jsonData', function(newVal) {
                if (newVal) {
                    try {
                        const parsedData = JSON.parse(newVal);
                        scope.headers = parsedData.settings.columns;
                        scope.data = parsedData.rows;
                    } catch (e) {
                        console.error('Invalid JSON string:', e);
                    }
                }
            });
        }
    };
});
